import{_ as t,p as d,q as a,a1 as n}from"./framework-96b046e1.js";const s="/images/lcd1602_1.png",e="/images/lcd1602_2.png",h="/images/lcd1602_3.png",c="/images/lcd1602_4.png",i={},o=n('<p><code>LCD1602A</code> 是单片机开发中常用的一种显示屏，可以显示简单的字母、数字、符号等内容。可以显示的字符数量为 <code>16x2</code>，也就是可以显示两行，每行<code>16</code>个字符。</p><p><code>LCD1602A</code> 的数据传输方式可以分为4位和8位两种，每块显示区域提供 <code>5x7</code> 个点阵+游标的显示模式。提供显示数据缓冲区 <code>DDRAM</code>、字符发生器<code>CGROM</code>和字符发生器<code>CGRAM</code>，可以用<code>CGRAM</code> 来存储自己定义的限多8个5x8点阵的图形字符的字模数据。提供了丰富的指令：<em>清除显示</em>、<em>游标回原点</em>、<em>显示开关</em>、<em>游标开关</em>、<em>显示字符闪烁</em>、<em>游标移位</em>、<em>显示移位元</em>等。提供内部上电自动复位电路，当外加电源电压超过<code>+4.5V</code>时，自动对模块进行初始化操作，将模块设置为默认的显示工作状态。</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>LCD1602 正反面图片： <img src="'+s+'" alt="LCD1602 正面"><img src="'+e+'" alt="LCD1602 反面"></p></div><h2 id="产品参数" tabindex="-1"><a class="header-anchor" href="#产品参数" aria-hidden="true">#</a> 产品参数</h2><ul><li>逻辑工作电压：(Vdd) +4.8~+5.2V</li><li>LCD驱动电压：(Vdd-Vo) +3.0~+5.0V</li></ul><h2 id="模块机械尺寸" tabindex="-1"><a class="header-anchor" href="#模块机械尺寸" aria-hidden="true">#</a> 模块机械尺寸</h2><p><img src="'+h+'" alt="LCD1602 机械尺寸"></p><h2 id="引脚定义" tabindex="-1"><a class="header-anchor" href="#引脚定义" aria-hidden="true">#</a> 引脚定义</h2><table><thead><tr><th>引脚号</th><th>引脚名称</th><th>I/O</th><th>描述</th></tr></thead><tbody><tr><td>1</td><td>GND</td><td>--</td><td>电源负极</td></tr><tr><td>2</td><td>VDD</td><td>--</td><td>电源正极</td></tr><tr><td>3</td><td>V0(VL)</td><td>--</td><td>液晶显示偏压信号</td></tr><tr><td>4</td><td>RS</td><td>|</td><td>指令/数据选择信号</td></tr><tr><td>5</td><td>RW</td><td>|</td><td>读写选择信号</td></tr><tr><td>6</td><td>E</td><td>|</td><td>使能信号</td></tr><tr><td>7</td><td>DB0</td><td>I/O</td><td>数据0</td></tr><tr><td>8</td><td>DB1</td><td>I/O</td><td>数据1</td></tr><tr><td>9</td><td>DB2</td><td>I/O</td><td>数据2</td></tr><tr><td>10</td><td>DB3</td><td>I/O</td><td>数据3</td></tr><tr><td>11</td><td>DB4</td><td>I/O</td><td>数据4</td></tr><tr><td>12</td><td>DB5</td><td>I/O</td><td>数据5</td></tr><tr><td>13</td><td>DB6</td><td>I/O</td><td>数据6</td></tr><tr><td>14</td><td>DB7</td><td>I/O</td><td>数据7</td></tr><tr><td>15</td><td>BL1</td><td>--</td><td>LED+(5V)</td></tr><tr><td>16</td><td>BL2</td><td>--</td><td>LED-(0V)</td></tr></tbody></table><p>一些引脚的介绍：</p><ul><li><code>VL</code>引脚：为液晶显示器对比度调整端，接正电源时对比度最弱，接地时对比度最高，对比度过高时会产生“鬼影”，使用时可以通过一个10K的电位器调整对比度；</li><li><code>RS</code>引脚：<strong>RS</strong>为寄存器选择，高电平时选择数据寄存器、低电平时选择指令寄存器</li><li><code>R/W</code>引脚：<strong>R/W</strong>为读写信号线，高电平时进行<strong>读</strong>操作，低电平时进行<strong>写</strong>操作。当<strong>RS</strong>和<strong>R/W</strong>共同为<strong>低</strong>电平时可以写入指令或者显示地址，当RS为低电平R/W为高电平时可以读忙信号，当RS为高电平R/W为低电平时可以写入数据。</li><li><code>EN</code>引脚：E端为使能端，当E端由高电平跳变成低电平时，液晶模块执行命令。</li></ul><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>【注】如果先打开使能，再进行其他配置的话，有可能传输的数据不是自己想要的。 作者：沙漠狼1998 https://www.bilibili.com/read/cv11024556?from=search 出处：bilibili</p></div><p>DDRAM ： <img src="'+c+`" alt="LCD1602 DDRAM"></p><h2 id="操作-1602-常用函数" tabindex="-1"><a class="header-anchor" href="#操作-1602-常用函数" aria-hidden="true">#</a> 操作 1602 常用函数</h2><ul><li>写指令函数</li><li>写数据函数</li><li>初始化函数</li></ul><h3 id="写数据" tabindex="-1"><a class="header-anchor" href="#写数据" aria-hidden="true">#</a> 写数据</h3><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token keyword">void</span> <span class="token function">write_data</span><span class="token punctuation">(</span><span class="token class-name">uint8_t</span> date<span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    LCDRS <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
    P0 <span class="token operator">=</span> date<span class="token punctuation">;</span>
    <span class="token function">LCDDelay</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    LCDEN <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
    <span class="token function">LCDDelay</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    LCDEN <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="写指令" tabindex="-1"><a class="header-anchor" href="#写指令" aria-hidden="true">#</a> 写指令</h3><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token keyword">void</span> <span class="token function">write_com</span><span class="token punctuation">(</span><span class="token class-name">uint8_t</span> com<span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    LCDRS <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
    P0 <span class="token operator">=</span> com<span class="token punctuation">;</span>
    <span class="token function">LCDDelay</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    LCDEN <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">;</span>
    <span class="token function">LCDDelay</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    LCDEN <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="初始化函数" tabindex="-1"><a class="header-anchor" href="#初始化函数" aria-hidden="true">#</a> 初始化函数</h3><p>LCD1602 初始化需要：</p><ol><li>设置 R/W 为低电平，低电平为写模式</li><li>屏幕设置模式：写指令 <code>38H</code></li><li>打开显示，关闭光标：写指令 <code>0CH</code></li><li>设置显示光标移动位置：写指令 <code>06H</code></li><li>设置字符显示位置：写指令（字符显示的起始位置）</li></ol><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token keyword">void</span> <span class="token function">init1602</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    <span class="token class-name">uint8_t</span> i <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
    LCDRW <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>
    <span class="token function">write_com</span><span class="token punctuation">(</span><span class="token number">0x38</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 显示屏初始化</span>
    <span class="token function">write_com</span><span class="token punctuation">(</span><span class="token number">0x0c</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 打开显示 无光标 无闪烁</span>
    <span class="token function">write_com</span><span class="token punctuation">(</span><span class="token number">0x06</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 当读或写一个字符是指针后一位</span>
    <span class="token function">write_com</span><span class="token punctuation">(</span><span class="token number">0x01</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 清屏</span>
    <span class="token function">write_com</span><span class="token punctuation">(</span><span class="token number">0x80</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 设置位置</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="指令列表" tabindex="-1"><a class="header-anchor" href="#指令列表" aria-hidden="true">#</a> 指令列表</h2><h3 id="_1、清屏" tabindex="-1"><a class="header-anchor" href="#_1、清屏" aria-hidden="true">#</a> 1、清屏</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>1</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：清除<code>DDRAM</code> 和 <code>AC</code>值</p><h3 id="_2、归为" tabindex="-1"><a class="header-anchor" href="#_2、归为" aria-hidden="true">#</a> 2、归为</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>1</td><td>*</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：<code>AC=0</code>, 光标，画面会 <code>HOME</code> 位</p><h3 id="_3、输入方式设置" tabindex="-1"><a class="header-anchor" href="#_3、输入方式设置" aria-hidden="true">#</a> 3、输入方式设置</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>1</td><td>I/D</td><td>S</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：设置光标，画面移动方式 其中：</p><ul><li>I/D=1 数据读、写操作后， AC自动增一</li><li>I/D=0 数据读、写操作后，AC自动减一</li><li>S=1 数据读、写操作后，画面平移</li><li>S=0 数据读、写操作后，画面不变</li></ul><h3 id="_4、显示开关控制" tabindex="-1"><a class="header-anchor" href="#_4、显示开关控制" aria-hidden="true">#</a> 4、显示开关控制</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>1</td><td>D</td><td>C</td><td>B</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：设置显示，光标及闪烁开、关 其中：</p><ul><li>D 表示显示开关：D=1为开，D=0为关</li><li>C 表示光标开关，C=1为开，C=0为关</li><li>B 表示闪烁开关，B=1为开，B=0为关</li></ul><h3 id="_5、光标、画面位移" tabindex="-1"><a class="header-anchor" href="#_5、光标、画面位移" aria-hidden="true">#</a> 5、光标、画面位移</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td><td>0</td><td>0</td><td>1</td><td>S/C</td><td>R/L</td><td>*</td><td>*</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：光标、画面移动，不影响<code>DDRAM</code> 其中：</p><ul><li>S/C=1 : 画面平原一个字符</li><li>S/C=0 : 光标平移一个字符位</li><li>R/L=1 : 右移， R/L=0 : 左移</li></ul><h3 id="_6、功能设置" tabindex="-1"><a class="header-anchor" href="#_6、功能设置" aria-hidden="true">#</a> 6、功能设置</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td><td>0</td><td>1</td><td>DL</td><td>N</td><td>F</td><td>*</td><td>*</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：工作方式设置（初始化指令） 其中：</p><ul><li>DL=1 设置为 8 位数据接口</li><li>DL=0 设置为 4 位数据接口</li><li>N=1 两行显示</li><li>N=0 一行显示</li><li>F=1 5X10点阵字符</li><li>F=0 5X7 点阵字符</li></ul><h3 id="_7、cgram-地址设置" tabindex="-1"><a class="header-anchor" href="#_7、cgram-地址设置" aria-hidden="true">#</a> 7、CGRAM 地址设置</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>0</td><td>1</td><td>A5</td><td>A4</td><td>A3</td><td>A2</td><td>A1</td><td>A0</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：设置<code>CGRAM</code>地址，<code>A5-A0 = 0~3FH</code></p><h3 id="_8、ddram-地址设置" tabindex="-1"><a class="header-anchor" href="#_8、ddram-地址设置" aria-hidden="true">#</a> 8、DDRAM 地址设置</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>1</td><td>A6</td><td>A5</td><td>A4</td><td>A3</td><td>A2</td><td>A1</td><td>A0</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：设置<code>DDRAM</code>地址</p><ul><li>N=0, 一行显示 A6~A0 = 0~4FH</li><li>N=1,两行显示 首行A6~A0 = 00H~2FH, 次行A6~A0 = 40H~67H</li></ul><h3 id="_9、读bf及ac值" tabindex="-1"><a class="header-anchor" href="#_9、读bf及ac值" aria-hidden="true">#</a> 9、读BF及AC值</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>0</td><td>1</td><td>BF</td><td>AC6</td><td>AC5</td><td>AC4</td><td>AC3</td><td>AC2</td><td>AC1</td><td>AC0</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：都忙BF值和地址计数器AC值 其中：</p><ul><li>BF=1 忙</li><li>BF=0 准备好，此时 AC 值意义为最近一次地址设置（CGRAM或DDRAM）定义</li></ul><h3 id="_10、写数据" tabindex="-1"><a class="header-anchor" href="#_10、写数据" aria-hidden="true">#</a> 10、写数据</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>1</td><td>0</td><td>D7</td><td>D6</td><td>D5</td><td>D4</td><td>D3</td><td>D2</td><td>D1</td><td>D0</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：根据最近设置的地址性质，数据写入<code>DDRAM</code>或<code>CGRAM</code>中</p><h3 id="_11、读数据" tabindex="-1"><a class="header-anchor" href="#_11、读数据" aria-hidden="true">#</a> 11、读数据</h3><table><thead><tr><th>RS</th><th>RW</th><th>DB7</th><th>DB6</th><th>DB5</th><th>DB4</th><th>DB3</th><th>DB2</th><th>DB1</th><th>DB0</th></tr></thead><tbody><tr><td>1</td><td>1</td><td>D7</td><td>D6</td><td>D5</td><td>D4</td><td>D3</td><td>D2</td><td>D1</td><td>D0</td></tr></tbody></table><p>运行时间（250KHz); 1.64us 功能：根据最近设置的地址性质，从<code>DDRAM</code>或<code>CGRAM</code>读数据</p>`,63),l=[o];function p(r,u){return d(),a("div",null,l)}const b=t(i,[["render",p],["__file","LCD1602A.html.vue"]]);export{b as default};
